n// 5',testCases:[{input:'minDistance("cat", "bat")',expected:"1"},{input:'minDistance("beach", "batch")',expected:"2"},{input:'minDistance("horse", "ros")',expected:"3"}]})}),(0,s.jsx)(l.A,{value:"python",label:"Python Solution",children:(0,s.jsx)(o.A,{language:"python",title:"Python Solution - Dynamic Programming",code:'def min_distance(s: str, t: str) -> int:\n  """\n  Find minimum edit distance between two strings\n  \n  Args:\n      s: Source string\n      t: Target string\n      \n  Returns:\n      int: Minimum number of operations\n  """\n  m = len(s)\n  n = len(t)\n  \n  # dp[i][j] = minimum operations to convert s[0...i-1] to t[0...j-1]\n  dp = [[0] * (n + 1) for _ in range(m + 1)]\n  \n  # Base cases\n  # dp[0][j] = j (insert j characters to empty string)\n  for j in range(n + 1):\n      dp[0][j] = j\n  \n  # dp[i][0] = i (delete i characters from s)\n  for i in range(m + 1):\n      dp[i][0] = i\n  \n  # Fill DP table\n  for i in range(1, m + 1):\n      for j in range(1, n + 1):\n          if s[i - 1] == t[j - 1]:\n              # Characters match, no operation needed\n              dp[i][j] = dp[i - 1][j - 1]\n          else:\n              # Three operations:\n              # 1. Delete: dp[i-1][j] (delete s[i-1])\n              # 2. Insert: dp[i][j-1] (insert t[j-1] into s)\n              # 3. Replace: dp[i-1][j-1] (replace s[i-1] with t[j-1])\n              dp[i][j] = 1 + min(\n                  dp[i - 1][j],     # delete\n                  dp[i][j - 1],     # insert\n                  dp[i - 1][j - 1]  # replace\n              )\n  \n  return dp[m][n]\n\n# Test cases\nprint(\'Example 1:\', min_distance("cat", "bat"))  \n# 1\n\nprint(\'Example 2:\', min_distance("beach", "batch"))  \n# 2\n\nprint(\'Example 3:\', min_distance("horse", "ros"))  \n# 3\n\nprint(\'Example 4:\', min_distance("intention", "execution"))  \n# 5',testCases:[{input:'min_distance("cat", "bat")',expected:"1"},{input:'min_distance("beach", "batch")',expected:"2"},{input:'min_distance